    fn measured_bincode<T: serde::Serialize>(value: &T) -> Vec<u8> {
        bincode::serde::encode_to_vec(value, bincode::config::legacy())
            .expect("test payload serialization")
    }

    fn encode_test_verifier_selection(selection: VerifierBundleSelectionV2) -> Vec<u8> {
        let mut bytes = Vec::with_capacity(NOVA_VERIFIER_SELECTION_BYTES_V2);
        bytes.extend_from_slice(&selection.binding.authority_digest);
        bytes.extend_from_slice(&selection.binding.profile_digest);
        bytes.extend_from_slice(&selection.binding.spec_digest);
        bytes.extend_from_slice(&selection.binding.pp_digest);
        bytes.extend_from_slice(&selection.binding.authority_generation.to_le_bytes());
        bytes.extend_from_slice(&selection.binding.activation_start_height.to_le_bytes());
        bytes.extend_from_slice(&selection.binding.activation_end_height.to_le_bytes());
        for value in selection.binding.expected_shape.values() {
            bytes.extend_from_slice(&value.to_le_bytes());
        }
        bytes.extend_from_slice(&selection.bundle_digest);
        assert_eq!(bytes.len(), NOVA_VERIFIER_SELECTION_BYTES_V2);
        bytes
    }

    fn decode_test_verifier_selection(bytes: &[u8]) -> VerifierBundleSelectionV2 {
        assert_eq!(
            bytes.len(),
            NOVA_VERIFIER_SELECTION_BYTES_V2,
            "verifier selection fixture has one exact encoding",
        );
        let mut cursor = 0;
        let authority_digest =
            super::take_fixed::<32>(bytes, &mut cursor).expect("selection authority digest");
        let profile_digest =
            super::take_fixed::<32>(bytes, &mut cursor).expect("selection profile digest");
        let spec_digest =
            super::take_fixed::<32>(bytes, &mut cursor).expect("selection spec digest");
        let pp_digest = super::take_fixed::<32>(bytes, &mut cursor).expect("selection PP digest");
        let authority_generation =
            super::take_u64_bundle(bytes, &mut cursor).expect("selection generation");
        let activation_start_height =
            super::take_u64_bundle(bytes, &mut cursor).expect("selection start height");
        let activation_end_height =
            super::take_u64_bundle(bytes, &mut cursor).expect("selection end height");
        let expected_shape = super::NovaAugmentedShapeV2 {
            primary_constraints: super::take_u64_bundle(bytes, &mut cursor)
                .expect("selection primary constraints"),
            secondary_constraints: super::take_u64_bundle(bytes, &mut cursor)
                .expect("selection secondary constraints"),
            primary_variables: super::take_u64_bundle(bytes, &mut cursor)
                .expect("selection primary variables"),
            secondary_variables: super::take_u64_bundle(bytes, &mut cursor)
                .expect("selection secondary variables"),
        };
        let bundle_digest =
            super::take_fixed::<32>(bytes, &mut cursor).expect("selection bundle digest");
        assert_eq!(cursor, bytes.len());
        VerifierBundleSelectionV2::new(
            VerifierBundleBindingV2 {
                authority_digest,
                profile_digest,
                spec_digest,
                pp_digest,
                authority_generation,
                activation_start_height,
                activation_end_height,
                max_cumulative_steps: RecursiveCircuitProfileV2::authority_pinned()
                    .max_cumulative_steps(),
                expected_shape,
            },
            bundle_digest,
        )
        .expect("authority-selected clean-process bundle")
    }

    fn read_bounded_verifier_artifact(env_name: &str, cap: usize) -> Vec<u8> {
        let path = PathBuf::from(
            std::env::var_os(env_name)
                .unwrap_or_else(|| panic!("missing verifier-only artifact path {env_name}")),
        );
        let metadata = fs::metadata(&path).unwrap_or_else(|error| {
            panic!("stat verifier-only artifact {}: {error}", path.display())
        });
        let length = usize::try_from(metadata.len()).expect("artifact length fits usize");
        assert!(
            length <= cap,
            "verifier-only artifact exceeds its safety cap"
        );
        let bytes = fs::read(&path).unwrap_or_else(|error| {
            panic!("read verifier-only artifact {}: {error}", path.display())
        });
        assert_eq!(bytes.len(), length, "artifact changed while being read");
        bytes
    }

    fn write_verifier_artifact(path: &Path, bytes: &[u8]) {
        let mut file = OpenOptions::new()
            .create_new(true)
            .write(true)
            .open(path)
            .unwrap_or_else(|error| {
                panic!("create verifier-only artifact {}: {error}", path.display())
            });
        file.write_all(bytes).unwrap_or_else(|error| {
            panic!("write verifier-only artifact {}: {error}", path.display())
        });
        file.sync_all().unwrap_or_else(|error| {
            panic!("sync verifier-only artifact {}: {error}", path.display())
        });
    }

    fn retain_t3_artifact(name: &str, bytes: &[u8]) {
        let Some(root) = std::env::var_os("Z00Z_NOVA_T3_ARTIFACT_DIR_V2") else {
            return;
        };
        let root = PathBuf::from(root);
        fs::create_dir_all(&root)
            .unwrap_or_else(|error| panic!("create retained T3 artifact root: {error}"));
        #[cfg(unix)]
        fs::set_permissions(&root, fs::Permissions::from_mode(0o700))
            .expect("set retained T3 artifact directory mode");
        let path = root.join(name);
        write_verifier_artifact(&path, bytes);
        #[cfg(unix)]
        fs::set_permissions(&path, fs::Permissions::from_mode(0o600))
            .expect("set retained T3 artifact mode");
        File::open(&root)
            .and_then(|directory| directory.sync_all())
            .expect("sync retained T3 artifact directory");
        eprintln!(
            "retained T3 artifact: path={}, bytes={}, sha256={}",
            path.display(),
            bytes.len(),
            super::lowercase_hex(sha256_256_simple(bytes)),
        );
    }

    #[test]
    fn test_nova_clean_verifier_process() {
        if std::env::var_os(NOVA_VERIFIER_ONLY_MARKER_V2).is_none() {
            return;
        }
        assert!(
            std::env::var_os(NOVA_WORKER_MARKER_V2).is_some(),
            "verifier-only evidence must descend from the bounded proof worker",
        );
        let selection_bytes = read_bounded_verifier_artifact(
            NOVA_VERIFIER_SELECTION_PATH_V2,
            NOVA_VERIFIER_SELECTION_BYTES_V2,
        );
        let selection = decode_test_verifier_selection(&selection_bytes);
        let bundle_bytes =
            read_bounded_verifier_artifact(NOVA_VERIFIER_BUNDLE_PATH_V2, NOVA_BUNDLE_SAFETY_CAP_V2);
        let envelope_bytes = read_bounded_verifier_artifact(
            NOVA_VERIFIER_ENVELOPE_PATH_V2,
            super::NOVA_ENVELOPE_SAFETY_CAP_V2,
        );

        // There is intentionally no PP/PK/setup object in this process. The
        // setup helper also has a marker guard, so any accidental indirect
        // setup path fails closed before parameter generation can start.
        let loaded = NovaVerifierBundleV2::load(&bundle_bytes, selection)
            .expect("clean process loads the authority-selected VK-only bundle");
        let fixture =
            canonical_mixed_nova_fixture(&loaded, RecursiveCircuitProfileV2::authority_pinned());
        let envelope = NovaProofEnvelopeV2::load(
            &envelope_bytes,
            &loaded,
            &fixture.public_input,
            DiagnosticSingleStepEnvelopeV2,
        )
        .expect("clean process loads the portable keyless envelope");
        let output = envelope
            .verify(
                &loaded,
                &fixture.public_input,
                DiagnosticSingleStepEnvelopeV2,
            )
            .expect("clean process verifies without prover material");
        assert_eq!(output, fixture.final_state.scalars());
        eprintln!(
            "clean verifier-only process: steps={}, bundle_bytes={}, envelope_bytes={}, setup_path=forbidden",
            fixture.events.len(),
            bundle_bytes.len(),
            envelope_bytes.len(),
        );
    }

    fn mutate_bundle_header(
        bundle: &[u8],
        mutate: impl FnOnce(&mut VerifierBundleHeaderV2),
    ) -> Vec<u8> {
        let mut header = VerifierBundleHeaderV2::decode(bundle).expect("canonical test header");
        mutate(&mut header);
        header.project_digest = super::bundle_project_digest(&header.canonical_prefix());
        let mut mutated = header.encode();
        mutated.extend_from_slice(&bundle[VERIFIER_BUNDLE_HEADER_BYTES_V2..]);
        mutated
    }

    fn assert_bundle_rejected_early(
        bundle: &[u8],
        binding: VerifierBundleBindingV2,
        expected_bundle_digest: [u8; 32],
    ) {
        let selection = VerifierBundleSelectionV2::new(binding, expected_bundle_digest)
            .expect("nonzero authority-selected test bundle digest");
        assert!(
            NovaVerifierBundleV2::load(bundle, selection).is_err(),
            "the bundle must reject before a proof decoder is reachable"
        );
    }

    fn assert_selected_invalid_vk_rejected(
        canonical_bundle: &[u8],
        binding: VerifierBundleBindingV2,
        invalid_vk: &[u8],
        label: &str,
    ) {
        assert!(
            super::decode_bincode::<super::NovaVerifierKey, { super::NOVA_VK_DECODE_CAP_V2 }>(
                invalid_vk
            )
            .is_err(),
            "{label} must fail the dependency key decoder"
        );
        assert_selected_forbidden_vk_rejected(canonical_bundle, binding, invalid_vk, label);
        eprintln!("selected invalid VK rejected at strict key decode: {label}");
    }

    fn assert_selected_forbidden_vk_rejected(
        canonical_bundle: &[u8],
        binding: VerifierBundleBindingV2,
        invalid_vk: &[u8],
        _label: &str,
    ) {
        let invalid_payload = z00z_utils::compression::zstd_compress(invalid_vk)
            .expect("compress selected invalid-key corpus");
        let mut header = VerifierBundleHeaderV2::decode(canonical_bundle)
            .expect("canonical selected verifier header");
        header.vk_digest = super::bundle_payload_digest(b"vk-canonical", invalid_vk);
        header.vk_payload_digest = super::bundle_payload_digest(b"vk-zstd", &invalid_payload);
        header.vk_decoded_bytes =
            u32::try_from(invalid_vk.len()).expect("bounded decoded VK length");
        header.vk_payload_bytes =
            u32::try_from(invalid_payload.len()).expect("bounded compressed VK length");
        header.project_digest = super::bundle_project_digest(&header.canonical_prefix());
        let mut selected_bundle = header.encode();
        selected_bundle.extend_from_slice(&invalid_payload);
        let selected_digest = super::bundle_payload_digest(b"verifier-bundle", &selected_bundle);
        assert_bundle_rejected_early(&selected_bundle, binding, selected_digest);
    }

    fn mutate_prover_material_header(
        material: &[u8],
        mutate: impl FnOnce(&mut super::ProverMaterialHeaderV2),
    ) -> Vec<u8> {
        let mut header = super::ProverMaterialHeaderV2::decode(material)
            .expect("canonical prover-material test header");
        mutate(&mut header);
        header.project_digest = super::prover_material_project_digest(&header.canonical_prefix());
        let mut mutated = header.encode();
        mutated.extend_from_slice(&material[super::PROVER_MATERIAL_HEADER_BYTES_V2..]);
        mutated
    }

    fn assert_prover_material_rejected(material: &[u8], binding: VerifierBundleBindingV2) {
        assert!(
            NovaProverMaterialV2::load(material, binding).is_err(),
            "private prover material must reject before entering recovery state"
        );
    }

    /// Audited control result kept test-only and intentionally independent of
    /// the production table.  Each row is `(phase, done)` in `ControlPhaseV2`
    /// numeric order, and each column is frozen core opcode order 1 through 13.
    /// Source opcodes 14 through 17 are audited independently below because
    /// they are phase-preserving authenticated-memory records.
    #[derive(Clone, Copy, Debug, PartialEq, Eq)]
    enum ExpectedControlEdgeV2 {
        Accept {
            next_phase: ControlPhaseV2,
            next_done: bool,
        },
        Reject(ControlTransitionRejectionV2),
    }

    const ILLEGAL: ExpectedControlEdgeV2 =
        ExpectedControlEdgeV2::Reject(ControlTransitionRejectionV2::IllegalEdge);
    const FINALIZED: ExpectedControlEdgeV2 =
        ExpectedControlEdgeV2::Reject(ControlTransitionRejectionV2::Finalized);
    const IDLE: ExpectedControlEdgeV2 = ExpectedControlEdgeV2::Accept {
        next_phase: ControlPhaseV2::Idle,
        next_done: false,
    };
    const REPLAY: ExpectedControlEdgeV2 = ExpectedControlEdgeV2::Accept {
        next_phase: ControlPhaseV2::Replay,
        next_done: false,
    };
    const PRECOMMIT: ExpectedControlEdgeV2 = ExpectedControlEdgeV2::Accept {
        next_phase: ControlPhaseV2::Precommit,
        next_done: false,
    };
    const CHALLENGE: ExpectedControlEdgeV2 = ExpectedControlEdgeV2::Accept {
        next_phase: ControlPhaseV2::Challenge,
        next_done: false,
    };
    const NET: ExpectedControlEdgeV2 = ExpectedControlEdgeV2::Accept {
        next_phase: ControlPhaseV2::Net,
        next_done: false,
    };
    const JMT: ExpectedControlEdgeV2 = ExpectedControlEdgeV2::Accept {
        next_phase: ControlPhaseV2::Jmt,
        next_done: false,
    };
    const PROMOTE: ExpectedControlEdgeV2 = ExpectedControlEdgeV2::Accept {
        next_phase: ControlPhaseV2::Promote,
        next_done: false,
    };
    const COMMIT: ExpectedControlEdgeV2 = ExpectedControlEdgeV2::Accept {
        next_phase: ControlPhaseV2::Commit,
        next_done: false,
    };
    const TRACE_CLOSURE: ExpectedControlEdgeV2 = ExpectedControlEdgeV2::Accept {
        next_phase: ControlPhaseV2::TraceClosure,
        next_done: false,
    };

    // This matrix is deliberately not generated from `CONTROL_TRANSITION_TABLE_V2`.
    // It freezes the core action grammar independently, including every rejected
    // phase/done/opcode tuple and all explicit hash-control self-loops.
    const EXPECTED_CONTROL_EDGE_MATRIX_V2: [[ExpectedControlEdgeV2; 13]; 18] = [
        [
            REPLAY, ILLEGAL, ILLEGAL, IDLE, IDLE, IDLE, ILLEGAL, ILLEGAL, ILLEGAL, ILLEGAL,
            ILLEGAL, ILLEGAL, ILLEGAL,
        ],
        [FINALIZED; 13],
        [
            ILLEGAL, REPLAY, REPLAY, REPLAY, REPLAY, REPLAY, PRECOMMIT, ILLEGAL, ILLEGAL, ILLEGAL,
            ILLEGAL, ILLEGAL, ILLEGAL,
        ],
        [FINALIZED; 13],
        [
            ILLEGAL, ILLEGAL, ILLEGAL, PRECOMMIT, PRECOMMIT, PRECOMMIT, ILLEGAL, CHALLENGE,
            ILLEGAL, ILLEGAL, ILLEGAL, ILLEGAL, ILLEGAL,
        ],
        [FINALIZED; 13],
        [
            ILLEGAL, ILLEGAL, ILLEGAL, CHALLENGE, CHALLENGE, CHALLENGE, ILLEGAL, ILLEGAL, NET,
            ILLEGAL, ILLEGAL, ILLEGAL, ILLEGAL,
        ],
        [FINALIZED; 13],
        [
            ILLEGAL, ILLEGAL, ILLEGAL, NET, NET, NET, ILLEGAL, ILLEGAL, NET, JMT, ILLEGAL, ILLEGAL,
            ILLEGAL,
        ],
        [FINALIZED; 13],
        [
            ILLEGAL, ILLEGAL, ILLEGAL, JMT, JMT, JMT, ILLEGAL, ILLEGAL, ILLEGAL, JMT, PROMOTE,
            ILLEGAL, ILLEGAL,
        ],
        [FINALIZED; 13],
        [
            ILLEGAL, ILLEGAL, ILLEGAL, PROMOTE, PROMOTE, PROMOTE, ILLEGAL, ILLEGAL, ILLEGAL,
            ILLEGAL, ILLEGAL, COMMIT, ILLEGAL,
        ],
        [FINALIZED; 13],
        [
            ILLEGAL,
            ILLEGAL,
            ILLEGAL,
            COMMIT,
            COMMIT,
            COMMIT,
            ILLEGAL,
            ILLEGAL,
            ILLEGAL,
            ILLEGAL,
            ILLEGAL,
            COMMIT,
            TRACE_CLOSURE,
        ],
        [FINALIZED; 13],
        [
            ILLEGAL,
            ILLEGAL,
            ILLEGAL,
            TRACE_CLOSURE,
            TRACE_CLOSURE,
            TRACE_CLOSURE,
            ILLEGAL,
            ILLEGAL,
            ILLEGAL,
            ILLEGAL,
            ILLEGAL,
            ILLEGAL,
            ILLEGAL,
        ],
        [FINALIZED; 13],
    ];

    fn expected_control_edge(
        phase: ControlPhaseV2,
        done: bool,
        opcode: crate::checkpoint::recursive_trace::RecursiveTraceOpcodeV2,
    ) -> ExpectedControlEdgeV2 {
        if opcode == RecursiveTraceOpcodeV2::TraceChunk {
            return if done {
                ExpectedControlEdgeV2::Reject(ControlTransitionRejectionV2::Finalized)
            } else {
                ExpectedControlEdgeV2::Accept {
                    next_phase: phase,
                    next_done: false,
                }
            };
        }
        if opcode == RecursiveTraceOpcodeV2::SourceMemoryWrite {
            return if done {
                ExpectedControlEdgeV2::Reject(ControlTransitionRejectionV2::Finalized)
            } else {
                ExpectedControlEdgeV2::Accept {
                    next_phase: phase,
                    next_done: false,
                }
            };
        }
        if opcode == RecursiveTraceOpcodeV2::UniquenessSorted {
            return if done {
                ExpectedControlEdgeV2::Reject(ControlTransitionRejectionV2::Finalized)
            } else if phase == ControlPhaseV2::Precommit {
                PRECOMMIT
            } else if phase == ControlPhaseV2::Challenge {
                CHALLENGE
            } else if phase == ControlPhaseV2::Net {
                NET
            } else {
                ILLEGAL
            };
        }
        if opcode == RecursiveTraceOpcodeV2::JmtMicroOp {
            return if done {
                ExpectedControlEdgeV2::Reject(ControlTransitionRejectionV2::Finalized)
            } else if phase == ControlPhaseV2::Jmt {
                JMT
            } else {
                ILLEGAL
            };
        }
        if matches!(
            opcode,
            RecursiveTraceOpcodeV2::ReplayInput | RecursiveTraceOpcodeV2::ReplayOutput
        ) && phase == ControlPhaseV2::Precommit
            && !done
        {
            return PRECOMMIT;
        }
        let state_index = (phase as usize) * 2 + usize::from(done);
        let opcode_index = usize::from(opcode as u8) - 1;
        EXPECTED_CONTROL_EDGE_MATRIX_V2[state_index][opcode_index]
    }

    fn circuit(
        anchors: CheckpointNovaAnchorsV2,
        phase: ControlPhaseV2,
        opcode: crate::checkpoint::recursive_trace::RecursiveTraceOpcodeV2,
        ordinal: u64,
    ) -> CheckpointNovaCircuitV2 {
        let witness = NovaStepWitnessV2::new(
            false,
            NovaTypedSourceEventV2::control(phase, opcode, ordinal),
        )
        .expect("test transition is legal");
        CheckpointNovaCircuitV2::new(anchors, witness)
    }

    fn source_event(
        phase: ControlPhaseV2,
        opcode: crate::checkpoint::recursive_trace::RecursiveTraceOpcodeV2,
        ordinal: u64,
        payload: &[u8],
    ) -> NovaTypedSourceEventV2 {
        let profile =
            crate::checkpoint::recursive_circuit::RecursiveCircuitProfileV2::authority_pinned();
        let object_id =
            crate::checkpoint::recursive_trace::structural_event_id(opcode, ordinal, payload);
        let source = crate::checkpoint::recursive_trace::RecursiveTraceEventV2::new(
            ordinal,
            opcode,
            object_id,
            payload.to_vec(),
            &profile,
        )
        .expect("bounded source event");
        NovaTypedSourceEventV2::from_source(phase, &source).expect("source event binding")
    }

    fn source_circuit(
        anchors: CheckpointNovaAnchorsV2,
        event: NovaTypedSourceEventV2,
    ) -> CheckpointNovaCircuitV2 {
        let witness = NovaStepWitnessV2::new(false, event).expect("legal source transition");
        CheckpointNovaCircuitV2::new(anchors, witness)
    }

    fn shape_of(
        circuit: &CheckpointNovaCircuitV2,
        state: &CheckpointRunningStateV2,
    ) -> (usize, usize, usize, [u8; 32]) {
        let mut cs = ShapeCS::<PallasEngine>::new();
        let inputs = state
            .scalars()
            .into_iter()
            .map(|value| AllocatedNum::alloc(&mut cs, || Ok(value)).expect("shape input alloc"))
            .collect::<Vec<_>>();
        let output = circuit
            .synthesize(&mut cs, &inputs)
            .expect("shape synthesis");
        assert_eq!(output.len(), RUNNING_STATE_ARITY_V2);
        let mut matrix = Vec::new();
        matrix.extend_from_slice(&(cs.num_constraints() as u64).to_le_bytes());
        matrix.extend_from_slice(&(cs.num_inputs() as u64).to_le_bytes());
        matrix.extend_from_slice(&(cs.num_aux() as u64).to_le_bytes());
        for constraint in &cs.constraints {
            for (lane, relation) in [
                (&b'A', &constraint.0),
                (&b'B', &constraint.1),
                (&b'C', &constraint.2),
            ] {
                matrix.push(*lane);
                matrix.extend_from_slice(&(relation.iter().count() as u64).to_le_bytes());
                for (variable, coefficient) in relation.iter() {
                    match variable.get_unchecked() {
                        Index::Input(index) => {
                            matrix.push(0);
                            matrix.extend_from_slice(&(index as u64).to_le_bytes());
                        }
                        Index::Aux(index) => {
                            matrix.push(1);
                            matrix.extend_from_slice(&(index as u64).to_le_bytes());
                        }
                    }
                    matrix.extend_from_slice(coefficient.to_repr().as_ref());
                }
            }
        }
        (
            cs.num_constraints(),
            cs.num_inputs(),
            cs.num_aux(),
            sha256_256_simple(&matrix),
        )
    }

    fn synthesize_test(
        circuit: &CheckpointNovaCircuitV2,
        state: &CheckpointRunningStateV2,
    ) -> (TestConstraintSystem<Scalar>, Vec<AllocatedNum<Scalar>>) {
        let mut cs = TestConstraintSystem::<Scalar>::new();
        let input = state
            .scalars()
            .into_iter()
            .enumerate()
            .map(|(index, value)| {
                AllocatedNum::alloc(cs.namespace(|| format!("input_{index}")), || Ok(value))
                    .expect("test input allocation")
            })
            .collect::<Vec<_>>();
        let output = circuit.synthesize(&mut cs, &input).expect("test synthesis");
        (cs, output)
    }

    fn synthesize_streaming_test(
        circuit: &CheckpointNovaCircuitV2,
        state: &CheckpointRunningStateV2,
    ) -> (StreamingTestCsV2, Vec<AllocatedNum<Scalar>>) {
        let mut cs = StreamingTestCsV2::new();
        let input = state
            .scalars()
            .into_iter()
            .enumerate()
            .map(|(index, value)| {
                AllocatedNum::alloc(cs.namespace(|| format!("input_{index}")), || Ok(value))
                    .expect("streaming test input allocation")
            })
            .collect::<Vec<_>>();
        let output = circuit
            .synthesize(&mut cs, &input)
            .expect("streaming test synthesis");
        (cs, output)
    }

    fn state_from_output(output: &[AllocatedNum<Scalar>]) -> CheckpointRunningStateV2 {
        assert_eq!(output.len(), RUNNING_STATE_ARITY_V2);
        CheckpointRunningStateV2 {
            cells: std::array::from_fn(|index| {
                output[index].get_value().expect("concrete test output")
            }),
        }
    }

    fn mixed_path(definition: u8, serial: u32, terminal: u8) -> SettlementPath {
        SettlementPath::new(
            DefinitionId::new([definition; 32]),
            SerialId::new(serial),
            TerminalId::new([terminal; 32]),
        )
    }

    fn mixed_item(path: SettlementPath, value: u64) -> StoreItem {
        let payload = AssetPackPlain {
            value,
            blinding: [3; 32],
            s_out: [4; 32],
        }
        .to_bytes();
        let leaf = AssetLeaf {
            asset_id: path.terminal_id().into_bytes(),
            serial_id: path.serial_id.get(),
            r_pub: [1; 32],
            owner_tag: [2; 32],
            c_amount: [5; 32],
            enc_pack: ZkPackEncrypted {
                version: 1,
                ciphertext: payload,
                tag: [0; 16],
            },
            range_proof: vec![9; 4],
            tag16: 11,
        };
        StoreItem::new(path, TerminalLeaf::from(leaf)).expect("mixed terminal item")
    }

    fn mixed_handoff(input: SettlementPath, output: StoreItem) -> SettlementExecHandoff {
        let tx = CheckpointExecTx::new(
            vec![CheckpointInRef::new(input.terminal_id(), input.serial_id)],
            vec![CheckpointExecOut::new(
                output.path().definition_id,
                output.terminal_leaf().expect("mixed terminal leaf").clone(),
            )
            .expect("mixed output")],
            vec![8],
        )
        .expect("mixed transaction row");
        SettlementExecHandoff::new(
            SettlementRouteCtx::new([9; 32], 1, 1, [10; 32]),
            vec![StoreOp::Delete(input), StoreOp::Put(Box::new(output))],
            vec![tx],
        )
    }

    fn mixed_checkpoint(
        root: &Path,
        pre_settlement_root: SettlementStateRoot,
        post_settlement_root: SettlementStateRoot,
        handoff: &SettlementExecHandoff,
        prior: super::RecursiveFinalizedIvcStateV2,
    ) -> (CheckpointFsStore, PrepFsStore, CheckpointId) {
        let draft = CheckpointDraft::new_settlement(
            CheckpointVersion::CURRENT,
            1,
            pre_settlement_root,
            post_settlement_root,
            vec![SpentEnt::new([0x51; 32])],
            vec![CreatedEnt::new([0x52; 32], [0x53; 32])],
        );
        let (snapshot, snapshot_id) =
            build_snapshot_v2(pre_settlement_root, Vec::new()).expect("mixed prep snapshot");
        let mut prep_store = PrepFsStore::new(root);
        assert_eq!(
            prep_store
                .save_snapshot(&snapshot)
                .expect("persist mixed prep snapshot"),
            snapshot_id
        );
        let exec = CheckpointExecInput::new_settlement(
            CheckpointExecVersion::CURRENT,
            snapshot_id,
            pre_settlement_root,
            handoff.txs().to_vec(),
        )
        .expect("mixed execution input");
        let mut checkpoint_store = CheckpointFsStore::new(root);
        let exec_id = checkpoint_store
            .save_exec_input(&exec)
            .expect("persist mixed execution input");
        let statement_core = crate::fixture_support::checkpoint_fixtures::statement_core(&exec)
            .with_prior_recursive_output_root(prior.digest());
        let manifest = crate::fixture_support::checkpoint_fixtures::archive_manifest_with_core(
            &draft,
            &exec,
            exec_id,
            statement_core,
        );
        let da_reference = crate::fixture_support::checkpoint_fixtures::da_reference(&manifest);
        checkpoint_store
            .stage_publication_contract(exec_id, &statement_core, &manifest, &da_reference)
            .expect("stage mixed publication contract");
        let link = checkpoint_store
            .seal_artifact(
                &draft,
                draft
                    .attest_proof(snapshot_id, exec_id)
                    .expect("mixed attested checkpoint proof"),
                snapshot_id,
                exec_id,
            )
            .expect("persist mixed checkpoint artifact and link");
        (checkpoint_store, prep_store, link.checkpoint_id())
    }

    struct MixedNovaFixtureV2 {
        _temp: TempDir,
        anchors: CheckpointNovaAnchorsV2,
        events: Vec<NovaTypedSourceEventV2>,
        initial: CheckpointRunningStateV2,
        final_state: CheckpointRunningStateV2,
        public_input: RecursiveNovaStepInputV2,
    }

    fn canonical_mixed_nova_fixture(
        loaded: &NovaVerifierBundleV2,
        profile: RecursiveCircuitProfileV2,
    ) -> MixedNovaFixtureV2 {
        mixed_nova_fixture_with_predecessor(loaded, profile, 1)
    }

    fn mixed_nova_fixture_with_predecessor(
        loaded: &NovaVerifierBundleV2,
        profile: RecursiveCircuitProfileV2,
        predecessor_tag: u8,
    ) -> MixedNovaFixtureV2 {
        assert_ne!(predecessor_tag, 0, "fixture predecessor must be nonzero");
        let temp = TempDir::new().expect("mixed Nova tempdir");
        let input = mixed_path(1, 1, 1);
        let output = mixed_item(mixed_path(2, 2, 2), 20);
        let handoff = mixed_handoff(input, output);
        let mut store = SettlementStore::new();
        store
            .put_settlement_item(mixed_item(input, 10))
            .expect("seed mixed pre-state");
        let pre_settlement_root = store
            .settlement_root_v2(7)
            .expect("mixed pre-settlement root");
        let pre_definition_root = store.recursive_v2_definition_root();
        let mut post = store.recursive_v2_preflight_clone();
        post.apply_test_exec_handoff_v2(handoff.clone(), temp.path())
            .expect("mixed transition preflight");
        let post_settlement_root = post
            .settlement_root_v2(7)
            .expect("mixed post-settlement root");
        let prior = super::RecursiveFinalizedIvcStateV2::cutover_fixture(
            CheckpointId::new([predecessor_tag; 32]),
            *pre_settlement_root.as_bytes(),
            pre_definition_root,
            [4; 32],
        )
        .expect("mixed cutover predecessor");
        let (checkpoint_store, prep_store, checkpoint_id) = mixed_checkpoint(
            temp.path(),
            pre_settlement_root,
            post_settlement_root,
            &handoff,
            prior,
        );
        let mut transition = CanonicalCheckpointTransitionV2::from_exec_with_verifier(
            temp.path(),
            profile,
            &checkpoint_store,
            &prep_store,
            checkpoint_id,
            &mut store,
            handoff,
            loaded
                .verifier_authority()
                .expect("loaded verifier authority"),
        )
        .expect("canonical mixed transition");
        let (evaluated, raw_events) = transition
            .evaluate_with_nova_events(&store)
            .expect("independent mixed evaluator and sole source replay");
        let public_input = loaded
            .build_public_input(&transition, &profile, evaluated, prior)
            .expect("mixed X_h from evaluator and loaded verifier");
        let verifier_authority = loaded
            .verifier_authority()
            .expect("loaded verifier authority");
        let context = transition
            .recursive_pre_uniqueness_context()
            .expect("mixed pre-uniqueness context");
        assert_eq!(
            verifier_authority.verifier_bundle_digest(),
            loaded.digest(),
            "P must bind the exact loaded verifier bundle"
        );
        let anchors = CheckpointNovaAnchorsV2::from_pre_uniqueness_context(context);
        let initial_scalars = super::expected_public_state(&public_input, 0, false)
            .expect("mixed initial public state");
        let initial = CheckpointRunningStateV2 {
            cells: initial_scalars
                .try_into()
                .expect("fixed mixed running-state arity"),
        };
        let mut phase = ControlPhaseV2::Idle;
        let mut events = Vec::with_capacity(raw_events.len());
        for source in raw_events {
            let typed = NovaTypedSourceEventV2::from_source(phase, &source)
                .expect("canonical mixed source has a Nova witness");
            phase = control_transition(phase, false, source.opcode())
                .expect("canonical mixed source has a legal edge")
                .next_phase;
            events.push(typed);
        }
        for index in 0..events.len().saturating_sub(1) {
            events[index] = events[index].clone().with_successor(&events[index + 1]);
        }
        let last = events.last().cloned().expect("nonempty mixed schedule");
        *events.last_mut().expect("mixed final event") = last.clone().with_successor(&last);

        let expected_final = super::expected_public_state(
            &public_input,
            u64::try_from(events.len()).expect("mixed step count"),
            true,
        )
        .expect("mixed expected successor state");
        let final_state = CheckpointRunningStateV2 {
            cells: expected_final
                .try_into()
                .expect("fixed mixed final-state arity"),
        };
        transition
            .finish(&store)
            .expect("mixed source remains immutable after evaluation");
        MixedNovaFixtureV2 {
            _temp: temp,
            anchors,
            events,
            initial,
            final_state,
            public_input,
        }
    }

    fn recompute_compressed_mixed_candidate(
        prover: &NovaProverMaterialV2,
        fixture: &MixedNovaFixtureV2,
    ) -> Vec<u8> {
        let first = fixture.events.first().expect("nonempty mixed candidate");
        let first_circuit = source_circuit(fixture.anchors.clone(), first.clone());
        let mut recursive =
            RecursiveSNARK::new(&prover.pp, &first_circuit, &fixture.initial.scalars())
                .expect("candidate recursive accumulator");
        recursive
            .prove_step(&prover.pp, &first_circuit)
            .expect("candidate first fold");
        for event in fixture.events.iter().skip(1) {
            recursive
                .prove_step(
                    &prover.pp,
                    &source_circuit(fixture.anchors.clone(), event.clone()),
                )
                .expect("candidate remaining fold");
        }
        assert_eq!(
            recursive
                .verify(&prover.pp, fixture.events.len(), &fixture.initial.scalars())
                .expect("candidate uncompressed verification"),
            fixture.final_state.scalars(),
            "the recomputed candidate must be a genuine satisfying proof for its own statement"
        );
        let compressed = Proof::prove(&prover.pp, &prover.pk, &recursive)
            .expect("compress recomputed mixed candidate");
        let bytes = measured_bincode(&compressed);
        assert!(bytes.len() <= NOVA_PROOF_MAX_BYTES_V2);
        bytes
    }

    fn canonical_mixed_schedule_counts() -> (usize, BTreeMap<u8, usize>, Vec<(u8, u8)>) {
        ensure_test_identity();
        let temp = TempDir::new().expect("mixed schedule tempdir");
        let profile = RecursiveCircuitProfileV2::authority_pinned();
        let input = mixed_path(1, 1, 1);
        let output = mixed_item(mixed_path(2, 2, 2), 20);
        let handoff = mixed_handoff(input, output);
        let mut store = SettlementStore::new();
        store
            .put_settlement_item(mixed_item(input, 10))
            .expect("seed mixed schedule pre-state");
        let pre_settlement_root = store
            .settlement_root_v2(7)
            .expect("mixed schedule pre-settlement root");
        let pre_definition_root = store.recursive_v2_definition_root();
        let mut post = store.recursive_v2_preflight_clone();
        post.apply_test_exec_handoff_v2(handoff.clone(), temp.path())
            .expect("mixed schedule transition preflight");
        let post_settlement_root = post
            .settlement_root_v2(7)
            .expect("mixed schedule post-settlement root");
        let prior = super::RecursiveFinalizedIvcStateV2::cutover_fixture(
            CheckpointId::new([1; 32]),
            *pre_settlement_root.as_bytes(),
            pre_definition_root,
            [4; 32],
        )
        .expect("mixed schedule cutover predecessor");
        let (checkpoint_store, prep_store, checkpoint_id) = mixed_checkpoint(
            temp.path(),
            pre_settlement_root,
            post_settlement_root,
            &handoff,
            prior,
        );
        let mut transition = CanonicalCheckpointTransitionV2::from_exec(
            temp.path(),
            profile,
            &checkpoint_store,
            &prep_store,
            checkpoint_id,
            &mut store,
            handoff,
        )
        .expect("repository-bound mixed schedule transition");
        let (_, events) = transition
            .evaluate_with_nova_events(&store)
            .expect("evaluate mixed schedule once");
        transition
            .finish(&store)
            .expect("finish mixed schedule source");
        let mut counts = BTreeMap::new();
        for event in &events {
            *counts.entry(event.opcode() as u8).or_insert(0) += 1;
        }
        let suffix = events
            .iter()
            .rev()
            .take(16)
            .map(|event| {
                let schema = decode_hash_control(event)
                    .map(|control| control.schema as u8)
                    .unwrap_or(0);
                (event.opcode() as u8, schema)
            })
            .collect::<Vec<_>>()
            .into_iter()
            .rev()
            .collect();
        (events.len(), counts, suffix)
    }

    #[test]
    fn test_mixed_schedule_reports_steps() {
        let (steps, counts, suffix) = canonical_mixed_schedule_counts();
        let expected = opcode_list()
            .into_iter()
            .map(|opcode| opcode as u8)
            .collect::<BTreeSet<_>>();
        assert_eq!(counts.keys().copied().collect::<BTreeSet<_>>(), expected);
        eprintln!(
            "canonical mixed Nova schedule: steps={steps}, opcode_counts={counts:?}, suffix_opcode_schema={suffix:?}"
        );
    }

