    #[test]
    fn test_replay_recovery_strict() {
        let binding = replay_binding_fixture();
        let recovery = super::NovaReplayRecoveryV2::new(binding, [0x77; 32], 2)
            .expect("replay recovery boundary");
        let bytes = recovery.canonical_bytes();
        assert_eq!(
            super::NovaReplayRecoveryV2::load(&bytes, recovery).expect("canonical replay recovery"),
            recovery
        );
        let mut corrupt = bytes;
        corrupt[1] ^= 1;
        assert!(super::NovaReplayRecoveryV2::load(&corrupt, recovery).is_err());
    }

    #[test]
    #[ignore = "real prover-material setup is milestone-only; run nova_milestone_tests.sh artifacts"]
    fn test_prover_material_rejects_substitution() {
        ensure_test_identity();
        let _guard = real_nova_proof_lock()
            .lock()
            .unwrap_or_else(|poisoned| poisoned.into_inner());
        let profile = RecursiveCircuitProfileV2::authority_pinned();
        let authority_store = SettlementStore::try_new().expect("active authority store");
        let authority = RecursiveAuthoritySnapshotV2::resolve_active_authority(&authority_store)
            .expect("active authority snapshot");
        let spec = RecursiveCircuitSpecV2::new(authority.authority().layout(), &profile)
            .expect("fixture circuit specification");
        let anchors = CheckpointNovaAnchorsV2::for_test();
        let state =
            CheckpointRunningStateV2::with_control(&anchors, ControlPhaseV2::Idle, 0, false);
        let step = circuit(
            anchors,
            ControlPhaseV2::Idle,
            RecursiveTraceOpcodeV2::BeginBlock,
            0,
        );
        let pp = setup_public_parameters_after_preflight(&step, &state)
            .expect("prover-material resource preflight and PP");
        let (pk, vk) = Proof::setup(&pp).expect("prover-material compression keys");
        let binding =
            VerifierBundleBindingV2::from_authority(&authority, &profile, &spec, &pp, 1, 5)
                .expect("prover-material authority binding");
        let prover = NovaProverMaterialV2::new(pp, pk);
        let material = prover
            .encode(binding)
            .expect("canonical private prover material");
        let bundle = prover
            .verifier_bundle(&vk, binding)
            .expect("canonical authority-selected verifier bundle");
        retain_t3_artifact("prover-material.bin", &material);
        retain_t3_artifact("verifier-bundle.bin", &bundle);
        let resolved =
            super::resolve_verifier_authority_v2(&material, &bundle, authority, &profile);
        let selected = NovaVerifierBundleV2::load(
            &bundle,
            VerifierBundleSelectionV2::new(
                binding,
                super::bundle_payload_digest(b"verifier-bundle", &bundle),
            )
            .expect("selected verifier bundle digest"),
        )
        .expect("strict selected verifier bundle");
        if super::super::authority_artifacts::ACTIVE_VERIFIER_BUNDLE_DIGEST_V2 == [0; 32] {
            assert!(resolved.is_err(), "an unset authority pin must fail closed");
        } else {
            assert_eq!(
                resolved.expect("pinned material and bundle resolve one authority"),
                selected
                    .verifier_authority()
                    .expect("selected bundle authority token")
            );
        }
        let mut wrong_bundle = bundle.clone();
        *wrong_bundle
            .last_mut()
            .expect("nonempty verifier bundle payload") ^= 1;
        assert!(super::resolve_verifier_authority_v2(
            &material,
            &wrong_bundle,
            authority,
            &profile,
        )
        .is_err());
        let canonical_header = super::ProverMaterialHeaderV2::decode(&material)
            .expect("canonical private prover-material header");
        eprintln!(
            "canonical prover material payload bytes: pp={}, pk={}, header={}, total={}",
            canonical_header.pp_payload_bytes,
            canonical_header.pk_payload_bytes,
            super::PROVER_MATERIAL_HEADER_BYTES_V2,
            material.len(),
        );
        let loaded = NovaProverMaterialV2::load(&material, binding)
            .expect("strict private prover-material roundtrip");
        assert_eq!(
            loaded.encode(binding).expect("canonical re-encode"),
            material,
            "accepted recovery material has exactly one wire encoding"
        );

        for mutate in [
            |header: &mut super::ProverMaterialHeaderV2| {
                header.selected_sha_batch_width = header.selected_sha_batch_width.saturating_add(1)
            },
            |header: &mut super::ProverMaterialHeaderV2| {
                header.authority_generation = header.authority_generation.saturating_add(1)
            },
            |header: &mut super::ProverMaterialHeaderV2| {
                header.activation_start_height = header.activation_start_height.saturating_add(1)
            },
            |header: &mut super::ProverMaterialHeaderV2| {
                header.activation_end_height = header.activation_end_height.saturating_add(1)
            },
            |header: &mut super::ProverMaterialHeaderV2| {
                header.primary_constraints = header.primary_constraints.saturating_add(1)
            },
            |header: &mut super::ProverMaterialHeaderV2| {
                header.secondary_constraints = header.secondary_constraints.saturating_add(1)
            },
            |header: &mut super::ProverMaterialHeaderV2| {
                header.primary_variables = header.primary_variables.saturating_add(1)
            },
            |header: &mut super::ProverMaterialHeaderV2| {
                header.secondary_variables = header.secondary_variables.saturating_add(1)
            },
            |header: &mut super::ProverMaterialHeaderV2| header.pp_digest[0] ^= 1,
            |header: &mut super::ProverMaterialHeaderV2| header.authority_digest[0] ^= 1,
            |header: &mut super::ProverMaterialHeaderV2| header.profile_digest[0] ^= 1,
            |header: &mut super::ProverMaterialHeaderV2| header.spec_digest[0] ^= 1,
            |header: &mut super::ProverMaterialHeaderV2| header.grammar_digest[0] ^= 1,
            |header: &mut super::ProverMaterialHeaderV2| header.shape_digest[0] ^= 1,
            |header: &mut super::ProverMaterialHeaderV2| header.source_digest[0] ^= 1,
            |header: &mut super::ProverMaterialHeaderV2| header.lockfile_digest[0] ^= 1,
            |header: &mut super::ProverMaterialHeaderV2| header.manifest_digest[0] ^= 1,
            |header: &mut super::ProverMaterialHeaderV2| {
                header.pp_payload_bytes = u32::try_from(super::NOVA_PUBLIC_PARAMS_MAX_BYTES)
                    .expect("PP safety cap fits u32")
                    .saturating_add(1)
            },
            |header: &mut super::ProverMaterialHeaderV2| {
                header.pk_payload_bytes = u32::try_from(super::NOVA_PROVER_KEY_MAX_BYTES)
                    .expect("PK safety cap fits u32")
                    .saturating_add(1)
            },
        ] {
            assert_prover_material_rejected(
                &mutate_prover_material_header(&material, mutate),
                binding,
            );
        }

        let mut trailing = material.clone();
        trailing.push(0);
        assert_prover_material_rejected(&trailing, binding);

        let header = super::ProverMaterialHeaderV2::decode(&material)
            .expect("canonical prover-material header");
        let pp_end = super::PROVER_MATERIAL_HEADER_BYTES_V2
            + usize::try_from(header.pp_payload_bytes).expect("PP length fits usize");
        let mut wrong_pk = material.clone();
        let pk_payload = &mut wrong_pk[pp_end..];
        let vk_digest_offset = pk_payload
            .len()
            .checked_sub(32)
            .expect("Nova PK contains the secondary VK digest");
        pk_payload[vk_digest_offset] ^= 1;
        super::decode_bincode::<super::NovaProverKey, { super::NOVA_PROVER_KEY_MAX_BYTES }>(
            pk_payload,
        )
        .expect("the substituted PK remains a canonical dependency object");
        let mut wrong_header = header;
        wrong_header.pk_payload_digest =
            super::bundle_payload_digest(b"prover-pk-canonical", pk_payload);
        wrong_header.project_digest =
            super::prover_material_project_digest(&wrong_header.canonical_prefix());
        wrong_pk[..super::PROVER_MATERIAL_HEADER_BYTES_V2].copy_from_slice(&wrong_header.encode());
        assert_prover_material_rejected(&wrong_pk, binding);
    }

    #[test]
    #[ignore = "full 1,727-step TestCS replay is milestone-only; run nova_milestone_tests.sh testcs"]
    fn test_mixed_fixture_satisfies_testcs() {
        ensure_test_identity();
        let _guard = real_nova_proof_lock()
            .lock()
            .unwrap_or_else(|poisoned| poisoned.into_inner());
        let profile = RecursiveCircuitProfileV2::authority_pinned();
        let authority_store = SettlementStore::try_new().expect("active authority store");
        let authority = RecursiveAuthoritySnapshotV2::resolve_active_authority(&authority_store)
            .expect("active authority snapshot");
        let spec = RecursiveCircuitSpecV2::new(authority.authority().layout(), &profile)
            .expect("fixture circuit specification");
        let anchors = CheckpointNovaAnchorsV2::for_test();
        let state =
            CheckpointRunningStateV2::with_control(&anchors, ControlPhaseV2::Idle, 0, false);
        let step = circuit(
            anchors,
            ControlPhaseV2::Idle,
            RecursiveTraceOpcodeV2::BeginBlock,
            0,
        );
        let pp = setup_public_parameters_after_preflight(&step, &state)
            .expect("mixed TestCS resource preflight and PP");
        let (pk, vk) = Proof::setup(&pp).expect("mixed TestCS compression keys");
        let binding =
            VerifierBundleBindingV2::from_authority(&authority, &profile, &spec, &pp, 1, 5)
                .expect("mixed TestCS authority binding");
        let bundle = NovaProverMaterialV2::new(pp, pk)
            .verifier_bundle(&vk, binding)
            .expect("mixed TestCS verifier bundle");
        let selection = VerifierBundleSelectionV2::new(
            binding,
            super::bundle_payload_digest(b"verifier-bundle", &bundle),
        )
        .expect("mixed TestCS authority-selected bundle digest");
        let loaded = NovaVerifierBundleV2::load(&bundle, selection)
            .expect("mixed TestCS strict verifier bundle");
        let fixture = canonical_mixed_nova_fixture(&loaded, profile);
        let mut current = fixture.initial.clone();
        for (index, event) in fixture.events.iter().enumerate() {
            let (cs, output) = synthesize_streaming_test(
                &source_circuit(fixture.anchors.clone(), event.clone()),
                &current,
            );
            assert!(
                cs.which_is_unsatisfied().is_none(),
                "mixed TestCS step {index}/{} opcode {:?} failed at {}",
                fixture.events.len(),
                event.opcode,
                cs.which_is_unsatisfied().unwrap_or("unknown constraint")
            );
            current = state_from_output(&output);
            if (index + 1) % 128 == 0 || index + 1 == fixture.events.len() {
                eprintln!(
                    "mixed TestCS progress={}/{}",
                    index + 1,
                    fixture.events.len()
                );
            }
        }
        assert_eq!(
            current.scalars(),
            fixture.final_state.scalars(),
            "independent complete TestCS replay must reach the sole expected endpoint"
        );
    }

    fn canonical_test_source_record(
        opcode: RecursiveTraceOpcodeV2,
        ordinal: u64,
        payload: &[u8],
    ) -> Vec<u8> {
        let mut record = Vec::with_capacity(super::TRACE_EVENT_HEADER_BYTES_V2 + payload.len());
        record.push(opcode as u8);
        record.extend_from_slice(&ordinal.to_le_bytes());
        record.extend_from_slice(&[0xA5; 32]);
        record.extend_from_slice(&(payload.len() as u32).to_le_bytes());
        record.extend_from_slice(payload);
        assert_eq!(
            record.len(),
            super::TRACE_EVENT_HEADER_BYTES_V2 + payload.len()
        );
        record
    }

    fn test_trace_chunks(record: &[u8], source_ordinal: u64) -> Vec<super::TraceChunkWitnessV2> {
        let chunk_count = record.len().div_ceil(super::TRACE_CANONICAL_CHUNK_BYTES_V2) as u32;
        record
            .chunks(super::TRACE_CANONICAL_CHUNK_BYTES_V2)
            .enumerate()
            .map(|(chunk_ordinal, chunk)| {
                let mut bytes = [0_u8; super::TRACE_CANONICAL_CHUNK_BYTES_V2];
                bytes[..chunk.len()].copy_from_slice(chunk);
                super::TraceChunkWitnessV2 {
                    source_ordinal,
                    chunk_ordinal: chunk_ordinal as u32,
                    chunk_count,
                    byte_count: chunk.len() as u8,
                    bytes,
                }
            })
            .collect()
    }

    fn synthesize_jmt_hierarchy_chunk(
        state: &CheckpointRunningStateV2,
        source_opcode: RecursiveTraceOpcodeV2,
        trace_chunk: &super::TraceChunkWitnessV2,
    ) -> (TestConstraintSystem<Scalar>, CheckpointRunningStateV2) {
        synthesize_jmt_hierarchy_step(
            state,
            source_opcode,
            RecursiveTraceOpcodeV2::TraceChunk,
            trace_chunk,
            &super::HashControlWitnessV2::inactive(),
        )
    }

    fn synthesize_jmt_hierarchy_step(
        state: &CheckpointRunningStateV2,
        source_opcode: RecursiveTraceOpcodeV2,
        step_opcode: RecursiveTraceOpcodeV2,
        trace_chunk: &super::TraceChunkWitnessV2,
        control_witness: &super::HashControlWitnessV2,
    ) -> (TestConstraintSystem<Scalar>, CheckpointRunningStateV2) {
        let mut state = state.clone();
        state.cells[super::SOURCE_BYTE_CONTEXT_START + super::BYTE_CONTEXT_HEADER_START_OFFSET] =
            Scalar::from(source_opcode as u8 as u64);
        let mut cs = TestConstraintSystem::<Scalar>::new();
        let z = state
            .scalars()
            .into_iter()
            .enumerate()
            .map(|(index, value)| {
                AllocatedNum::alloc(cs.namespace(|| format!("input_{index}")), || Ok(value))
                    .expect("JMT test input allocation")
            })
            .collect::<Vec<_>>();
        let opcode = AllocatedNum::alloc(cs.namespace(|| "test_step_opcode"), || {
            Ok(Scalar::from(step_opcode as u8 as u64))
        })
        .expect("test step opcode allocation");
        let opcode_selectors = super::opcode_selectors(&mut cs, &opcode).expect("opcode selectors");
        let allocated_chunk =
            super::allocate_trace_chunk(cs.namespace(|| "trace_chunk"), trace_chunk)
                .expect("trace chunk allocation");
        let control =
            super::allocate_hash_control(cs.namespace(|| "hash_control"), control_witness)
                .expect("hash-control allocation");
        let trace_chunk_selector =
            &opcode_selectors[usize::from(RecursiveTraceOpcodeV2::TraceChunk as u8 - 1)];
        let outputs = super::synthesize_jmt_hierarchy_payload(
            cs.namespace(|| "jmt_hierarchy_payload"),
            &z,
            &opcode_selectors,
            trace_chunk_selector,
            &allocated_chunk,
            &control,
        )
        .expect("JMT/hierarchy payload synthesis");
        for (index, value) in outputs.cells {
            state.cells[index] = value.get_value().expect("concrete JMT payload output");
        }
        (cs, state)
    }

